import { Bar } from 'react-chartjs-2';
import { Typography } from '@material-ui/core';
const BarChart = (props) => {

    // const keywords = props.keywords;
    // const country = props.country;

    const predictions = props.data.predictions;
    const avgPrice = props.data.avgPrice;
    const avgRating = props.data.avgRating;
    const soldUnits = props.data.soldUnits;



    return (
        <div>
            <Bar
                data={{
                    labels: ['Positive', 'Negative'],
                    datasets: [
                        {
                            label: 'Sentiment Review',
                            data: predictions,
                            backgroundColor: [
                                'rgba(255, 99, 132, 0.2)',
                                'rgba(54, 162, 235, 0.2)',

                            ],
                            borderColor: [
                                'rgba(255, 99, 132, 0.2)',
                                'rgba(54, 162, 235, 0.2)',
                            ],
                            borderWidth: 1,
                        }
                    ]
                }}
                height={200}
                width={400}
                options={{
                    // maintainAspectRatio: false,
                    responsive: true,
                    scales: {
                        yAxes: [
                            {
                                ticks: {
                                    beginAtZero: true
                                },
                                gridLines: {
                                    display: false
                                }
                            }
                        ],
                        xAxes: [
                            {
                                gridLines: {
                                    display: false
                                }
                            }
                        ]
                    }
                }}
            />
            <Typography variant="h1">Average Price: {avgPrice}</Typography>
            <div>Average Price: {avgPrice}</div>
            <div>Average Rating: {avgRating}</div>
            <div>Sold Units: {soldUnits}</div>
        </div>
    );
}

export default BarChart;
